import sailpoint.api.*;
import sailpoint.object.*;
import sailpoint.object.EmailTemplate;
import sailpoint.object.EmailOptions;

EmailTemplate template=context.getObjectByName(EmailTemplate.class,emailTemplateName);
if(template!=null){
// EmailTemplate template=new EmailTemplate();
// template.setName("emailTemplate for Workflow schedule Demo");

// String toMail="mahesh.nattali@eshiam.com";

Map args=new HashMap();
args.put("identityName",identityName);
args.put("emailTemplateName" ,emailTemplateName);

EmailOptions ops=new EmailOptions(identityName,args);
context.sendEmailNotification(template,ops);
}
else
{
log.error("ERROR:EmailTemplate Not Found");
}
